CREATE TABLE repositories (id TEXT PRIMARY KEY, path TEXT NOT NULL UNIQUE, name TEXT NOT NULL, preferences TEXT NOT NULL DEFAULT '{}', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE machine_preferences (key TEXT PRIMARY KEY, value TEXT NOT NULL);
CREATE TABLE registry_snapshots (id TEXT PRIMARY KEY, source TEXT NOT NULL, version TEXT NOT NULL, snapshot TEXT NOT NULL, fetched_at DATETIME NOT NULL, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE registry_refreshes (id TEXT PRIMARY KEY, status TEXT NOT NULL, started_at DATETIME NOT NULL, finished_at DATETIME, error TEXT, snapshot_fetched_at DATETIME);
CREATE TABLE installed_agents (id TEXT NOT NULL, version TEXT NOT NULL, source TEXT NOT NULL, license TEXT NOT NULL, distribution TEXT NOT NULL, package_specifier TEXT NOT NULL, launch TEXT NOT NULL, registry_snapshot_fetched_at TEXT NOT NULL, integrity_status TEXT NOT NULL, expected_digest TEXT, observed_digest TEXT, installation_id TEXT NOT NULL DEFAULT '', provenance TEXT, installation_root TEXT, status TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, failure TEXT, is_default INTEGER NOT NULL DEFAULT 0, readiness_status TEXT NOT NULL DEFAULT 'unknown', readiness_error TEXT, readiness_failure TEXT, protocol_version INTEGER, capabilities TEXT, auth_methods TEXT NOT NULL DEFAULT '[]', raw_initialize TEXT, probed_at TEXT, PRIMARY KEY (id, version, distribution, installation_id));
CREATE TABLE installation_operations (id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, version TEXT NOT NULL, package_specifier TEXT NOT NULL, distribution TEXT NOT NULL DEFAULT 'npx', installation_id TEXT NOT NULL DEFAULT '', phase TEXT NOT NULL DEFAULT 'resolving', temporary_root TEXT, published_root TEXT, recovery_metadata TEXT, status TEXT NOT NULL, started_at TEXT NOT NULL, finished_at TEXT, error TEXT, failure TEXT, error_code TEXT, diagnostic TEXT, activation_status TEXT NOT NULL DEFAULT 'not_started', activation_started_at TEXT, activation_finished_at TEXT, activation_error TEXT, activation_error_code TEXT, activation_diagnostic TEXT);
CREATE TABLE agent_authentication_operations (id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, version TEXT NOT NULL, installation_id TEXT NOT NULL DEFAULT '', method_id TEXT NOT NULL, method_name TEXT NOT NULL, method_type TEXT NOT NULL DEFAULT 'agent', status TEXT NOT NULL, started_at TEXT NOT NULL, finished_at TEXT, error TEXT, failure TEXT, terminal_exit_code INTEGER, terminal_signal INTEGER, terminal_output_truncated INTEGER NOT NULL DEFAULT 0, terminal_last_activity_at TEXT, terminal_diagnostic TEXT);
CREATE TABLE agent_removal_operations (id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, version TEXT NOT NULL, installation_id TEXT NOT NULL, status TEXT NOT NULL, started_at TEXT NOT NULL, finished_at TEXT, error TEXT, error_code TEXT, diagnostic TEXT, references_json TEXT NOT NULL DEFAULT '[]');
CREATE TABLE agent_removal_tombstones (installation_id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, version TEXT NOT NULL, provenance TEXT NOT NULL, removed_at TEXT NOT NULL, removal_operation_id TEXT NOT NULL);
CREATE TABLE agent_credential_bindings (installation_id TEXT NOT NULL, variable_name TEXT NOT NULL, credential_ref TEXT NOT NULL, secret INTEGER NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, PRIMARY KEY (installation_id, variable_name));

CREATE TABLE workflow_profiles (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, name TEXT NOT NULL, permission_policy TEXT NOT NULL, unattended_authorized INTEGER NOT NULL DEFAULT 0, timeout_ms INTEGER NOT NULL, max_retries INTEGER NOT NULL, verification_commands TEXT NOT NULL, require_decorrelated_builder_validator INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE (repository_id, id), FOREIGN KEY (repository_id) REFERENCES repositories(id) ON DELETE CASCADE);
CREATE TABLE agent_assignments (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, profile_id TEXT NOT NULL, role TEXT NOT NULL, agent_id TEXT NOT NULL, agent_version TEXT NOT NULL, model TEXT, mode TEXT, agent_provenance TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(repository_id, id), UNIQUE(repository_id, profile_id, role), FOREIGN KEY (repository_id, profile_id) REFERENCES workflow_profiles(repository_id, id) ON DELETE CASCADE);

CREATE TABLE tasks (id INTEGER PRIMARY KEY AUTOINCREMENT, repository_id TEXT NOT NULL, slug TEXT NOT NULL, title TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'backlog', spec_markdown TEXT NOT NULL DEFAULT '', retry_count INTEGER NOT NULL DEFAULT 0, last_failure TEXT, workflow_profile_id TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE(repository_id, id), UNIQUE(repository_id, slug), FOREIGN KEY (repository_id) REFERENCES repositories(id) ON DELETE CASCADE, FOREIGN KEY (repository_id, workflow_profile_id) REFERENCES workflow_profiles(repository_id, id));
CREATE TABLE runs (id INTEGER PRIMARY KEY AUTOINCREMENT, repository_id TEXT NOT NULL, task_id INTEGER NOT NULL, role TEXT NOT NULL, agent_id TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'running', prompt TEXT, commit_sha TEXT, started_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, ended_at DATETIME, error TEXT, agent_version TEXT NOT NULL DEFAULT 'legacy', capabilities TEXT NOT NULL DEFAULT '{}', assignment_config TEXT NOT NULL DEFAULT '{}', supervisor_session_id TEXT, operation_id TEXT, verification_status TEXT, verification_output TEXT, agent_provenance TEXT NOT NULL DEFAULT '{}', failure TEXT, auth_recovery_resolved_at DATETIME, superseded_by_run_id INTEGER, UNIQUE(repository_id, id), FOREIGN KEY (repository_id, task_id) REFERENCES tasks(repository_id, id), FOREIGN KEY (repository_id, superseded_by_run_id) REFERENCES runs(repository_id, id));
CREATE TABLE run_operations (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, run_id INTEGER NOT NULL, operation TEXT NOT NULL, status TEXT NOT NULL, diagnostic TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, ended_at DATETIME, FOREIGN KEY (repository_id, run_id) REFERENCES runs(repository_id, id) ON DELETE CASCADE);
CREATE TABLE run_events (id INTEGER PRIMARY KEY AUTOINCREMENT, repository_id TEXT NOT NULL, run_id INTEGER NOT NULL, seq INTEGER NOT NULL, type TEXT NOT NULL, payload TEXT NOT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (repository_id, run_id) REFERENCES runs(repository_id, id));
CREATE TABLE spec_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, repository_id TEXT NOT NULL, task_id INTEGER NOT NULL, role TEXT NOT NULL, content TEXT NOT NULL, prompt_status TEXT, failure TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (repository_id, task_id) REFERENCES tasks(repository_id, id));
CREATE TABLE chat_threads (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, repo_root TEXT NOT NULL, cwd TEXT NOT NULL, agent_id TEXT NOT NULL, agent_version TEXT NOT NULL DEFAULT 'legacy', title TEXT NOT NULL DEFAULT 'New session', status TEXT NOT NULL DEFAULT 'active', archived INTEGER NOT NULL DEFAULT 0, pinned INTEGER NOT NULL DEFAULT 0, task_slug TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, last_message_at DATETIME, scratch_markdown TEXT NOT NULL DEFAULT '', agent_provenance TEXT NOT NULL DEFAULT '{}', session_config_options TEXT NOT NULL DEFAULT '[]', session_modes TEXT, session_initialized INTEGER NOT NULL DEFAULT 0, failure TEXT, UNIQUE(repository_id, id), FOREIGN KEY (repository_id) REFERENCES repositories(id) ON DELETE CASCADE);
CREATE TABLE chat_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, repository_id TEXT NOT NULL, thread_id TEXT NOT NULL, role TEXT NOT NULL, content TEXT NOT NULL, attachment_ids TEXT NOT NULL DEFAULT '[]', prompt_status TEXT, failure TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (repository_id, thread_id) REFERENCES chat_threads(repository_id, id) ON DELETE CASCADE);
CREATE TABLE chat_attachments (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, thread_id TEXT NOT NULL, filename TEXT NOT NULL, mime_type TEXT NOT NULL, byte_size INTEGER NOT NULL, storage_name TEXT NOT NULL UNIQUE, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (repository_id, thread_id) REFERENCES chat_threads(repository_id, id) ON DELETE CASCADE);
CREATE TABLE acp_sessions (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, owner_type TEXT NOT NULL, owner_id TEXT NOT NULL, agent_id TEXT NOT NULL, agent_version TEXT NOT NULL, acp_session_id TEXT, capabilities TEXT NOT NULL DEFAULT '{}', status TEXT NOT NULL DEFAULT 'starting', recovery_metadata TEXT NOT NULL DEFAULT '{}', diagnostic TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, started_at DATETIME, ended_at DATETIME, agent_provenance TEXT NOT NULL DEFAULT '{}', failure TEXT, UNIQUE(repository_id, id), FOREIGN KEY (repository_id) REFERENCES repositories(id) ON DELETE CASCADE);
CREATE TABLE acp_prompts (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, session_id TEXT NOT NULL, prompt TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'running', cancellation_requested_at DATETIME, diagnostic TEXT, started_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, ended_at DATETIME, content TEXT NOT NULL DEFAULT '{}', failure TEXT, message_id INTEGER, resubmission_of TEXT, UNIQUE(repository_id, id), FOREIGN KEY (repository_id, session_id) REFERENCES acp_sessions(repository_id, id) ON DELETE CASCADE);
CREATE TABLE acp_events (id INTEGER PRIMARY KEY AUTOINCREMENT, repository_id TEXT NOT NULL, session_id TEXT NOT NULL, prompt_id TEXT, seq INTEGER NOT NULL, type TEXT NOT NULL, normalized TEXT NOT NULL, raw_payload TEXT NOT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (repository_id, session_id) REFERENCES acp_sessions(repository_id, id) ON DELETE CASCADE, FOREIGN KEY (repository_id, prompt_id) REFERENCES acp_prompts(repository_id, id) ON DELETE SET NULL);
CREATE TABLE permission_requests (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, session_id TEXT NOT NULL, thread_id TEXT NOT NULL, request_id TEXT NOT NULL, tool TEXT NOT NULL, kind TEXT, raw_request TEXT NOT NULL, options TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'pending', selected_option_id TEXT, decision_action TEXT, diagnostic TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, resolved_at DATETIME, FOREIGN KEY (repository_id, session_id) REFERENCES acp_sessions(repository_id, id) ON DELETE CASCADE);
CREATE TABLE spec_author_sessions (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, task_id INTEGER NOT NULL, workflow_profile_id TEXT NOT NULL, assignment_id TEXT NOT NULL, agent_id TEXT NOT NULL, agent_version TEXT NOT NULL, capabilities TEXT NOT NULL DEFAULT '{}', assignment_config TEXT NOT NULL DEFAULT '{}', acp_session_id TEXT, supervisor_session_id TEXT, status TEXT NOT NULL DEFAULT 'active', agent_provenance TEXT NOT NULL DEFAULT '{}', failure TEXT, message_id INTEGER, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE(repository_id, id), FOREIGN KEY (repository_id, task_id) REFERENCES tasks(repository_id, id), FOREIGN KEY (repository_id, workflow_profile_id) REFERENCES workflow_profiles(repository_id, id));
CREATE TABLE spec_author_operations (id INTEGER PRIMARY KEY AUTOINCREMENT, repository_id TEXT NOT NULL, author_session_id TEXT NOT NULL, operation TEXT NOT NULL, status TEXT NOT NULL, diagnostic TEXT, failure TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (repository_id, author_session_id) REFERENCES spec_author_sessions(repository_id, id) ON DELETE CASCADE);

CREATE INDEX idx_workflow_profiles_repository ON workflow_profiles(repository_id);
CREATE INDEX idx_agent_assignments_repository_profile ON agent_assignments(repository_id, profile_id);
CREATE INDEX idx_tasks_repository ON tasks(repository_id, created_at DESC, id DESC);
CREATE INDEX idx_runs_repository_task ON runs(repository_id, task_id);
CREATE INDEX idx_run_operations_repository_run ON run_operations(repository_id, run_id);
CREATE INDEX idx_run_events_repository_run ON run_events(repository_id, run_id, seq);
CREATE INDEX idx_spec_messages_repository_task ON spec_messages(repository_id, task_id);
CREATE INDEX idx_chat_threads_repository ON chat_threads(repository_id, updated_at DESC);
CREATE INDEX idx_chat_messages_repository_thread ON chat_messages(repository_id, thread_id, id);
CREATE INDEX idx_chat_attachments_repository_thread ON chat_attachments(repository_id, thread_id);
CREATE INDEX idx_acp_sessions_repository ON acp_sessions(repository_id, created_at DESC);
CREATE INDEX idx_acp_prompts_repository_session ON acp_prompts(repository_id, session_id);
CREATE INDEX idx_acp_events_repository_session ON acp_events(repository_id, session_id, seq);
CREATE INDEX idx_permission_requests_repository_thread ON permission_requests(repository_id, thread_id);
CREATE INDEX idx_spec_author_sessions_repository_task ON spec_author_sessions(repository_id, task_id);
CREATE INDEX idx_spec_author_operations_repository_session ON spec_author_operations(repository_id, author_session_id);
CREATE UNIQUE INDEX idx_installed_agents_identity ON installed_agents(id, version, distribution, installation_id);
